steps.script:
var m = tree.current_scene
var sc = m.shooting_controller
for i in range(sc.unit_selector.item_count):
	if str(sc.unit_selector.get_item_metadata(i)) == "U_BATTLEWAGON_A":
		sc.unit_selector.select(i)
		sc.unit_selector.item_selected.emit(i)
		break
return str(sc.active_shooter_id)

var sc = tree.current_scene.shooting_controller
var ring = sc.eligible_targets.keys()
ring.sort()
return str(PadRouter.target_highlight_id) == str(ring[0])

var sc = tree.current_scene.shooting_controller
var ring = sc.eligible_targets.keys()
ring.sort()
return str(PadRouter.target_highlight_id) == str(ring[1])

var ph = PhaseManager.get_current_phase_instance()
var targets = {}
for a in ph.pending_assignments:
	targets[str(a.target_unit_id)] = true
return targets.size()
